class Solution:
    def numSpecial(self, mat):
        rows = len(mat)
        cols = len(mat[0]) if rows else 0
        count = 0
        for i in range(rows):
            for j in range(cols):
                if mat[i][j] != 1:
                    continue
                row_ones = sum(1 for c in range(cols) if mat[i][c] == 1)
                col_ones = sum(1 for r in range(rows) if mat[r][j] == 1)
                if row_ones == 1 and col_ones == 1:
                    count += 1
        return count

