class Solution:
    def numSpecial(self, mat):
        rows = len(mat)
        cols = len(mat[0]) if rows else 0
        row_sum = [sum(row) for row in mat]
        col_sum = [sum(mat[r][c] for r in range(rows)) for c in range(cols)]
        count = 0
        for i in range(rows):
            for j in range(cols):
                if mat[i][j] == 1 and row_sum[i] == 1 and col_sum[j] == 1:
                    count += 1
        return count

